class JavaMath:
    PI = math.pi
    E = math.e
    toRadians = staticmethod(math.radians)
    toDegrees = staticmethod(math.degrees)
    max = staticmethod(max)
    min = staticmethod(min)
    abs = staticmethod(abs)
    round = staticmethod(round)


for _math_name in dir(math):
    if not _math_name.startswith("_") and not hasattr(JavaMath, _math_name):
        _math_value = getattr(math, _math_name)
        setattr(JavaMath, _math_name, staticmethod(_math_value) if callable(_math_value) else _math_value)


class JavaRotorSpec:
    DEFAULT_BLADE_PITCH_TO_DIAMETER_RATIO = 0.85
    HUB_BIASED_PROP_INERTIA_COEFFICIENT = 0.25
    UNIFORM_BLADE_PROP_INERTIA_COEFFICIENT = 1.0 / 3.0
    TIP_BIASED_PROP_INERTIA_COEFFICIENT = 0.50

    @staticmethod
    def defaultBladePitchMeters(radiusMeters: float) -> float:
        return max(0.01, radiusMeters * 2.0 * JavaRotorSpec.DEFAULT_BLADE_PITCH_TO_DIAMETER_RATIO)

    @staticmethod
    def estimatedPropInertiaKgMetersSquared(radiusMeters: float, propMassGrams: float, massDistributionCoefficient: float) -> float:
        if not all(math.isfinite(value) for value in (radiusMeters, propMassGrams, massDistributionCoefficient)):
            return 0.0
        safe_radius_m = max(0.0, radiusMeters)
        safe_mass_kg = max(0.0, propMassGrams) * 0.001
        safe_coefficient = min(1.0, max(0.0, massDistributionCoefficient))
        return safe_coefficient * safe_mass_kg * safe_radius_m * safe_radius_m

    @staticmethod
    def estimatedUniformBladePropInertiaKgMetersSquared(radiusMeters: float, propMassGrams: float) -> float:
        return JavaRotorSpec.estimatedPropInertiaKgMetersSquared(
            radiusMeters,
            propMassGrams,
            JavaRotorSpec.UNIFORM_BLADE_PROP_INERTIA_COEFFICIENT,
        )
