def aiio_sample_definition_from_hdf5_member(member_name: str) -> dict[str, float | str]:
    prefix = member_name.rsplit("/processed_data/test/data.hdf5", 1)[0]
    parts = prefix.split("/")
    mode = "unknown"
    trajectory = "unknown"
    sequence = "unknown"
    reference_speed_label = "unknown"
    reference_speed_m_s = float("nan")
    if len(parts) >= 6 and parts[3] == "manual":
        mode = "manual"
        trajectory = parts[4]
        sequence = parts[5]
        speed_map = {"low": 5.0, "medium": 8.0, "high": 14.0}
        reference_speed_m_s = speed_map.get(trajectory, float("nan"))
        reference_speed_label = f"manual_{trajectory}_{fmt(reference_speed_m_s, 0)}m_s"
        name = f"AIIO_manual_{trajectory}_{sequence}_test"
    elif len(parts) >= 5:
        mode = "autonomous"
        trajectory = parts[3]
        sequence = parts[4]
        speed_match = re.search(r"spd_(\d+(?:\.\d+)?)", sequence)
        reference_speed_m_s = float(speed_match.group(1)) if speed_match else float("nan")
        reference_speed_label = f"directory_{sequence}"
        name = f"AIIO_{trajectory}_{sequence}_test"
    else:
        name = re.sub(r"[^A-Za-z0-9]+", "_", prefix).strip("_")
    return {
        "name": name,
        "mode": mode,
        "trajectory": trajectory,
        "sequence": sequence,
        "split": "test",
        "reference_speed_label": reference_speed_label,
        "reference_speed_m_s": reference_speed_m_s,
        "hdf5_member": member_name,
        "groundtruth_member": f"{prefix}/processed_data/test/stamped_groundtruth_imu.txt",
        "metadata_member": f"{prefix}/metadata.yaml",
    }


def discover_aiio_test_sample_definitions() -> list[dict[str, float | str]]:
    hdf5_members: list[str] = []
    if AIIO_ARCHIVE.exists():
        with tarfile.open(AIIO_ARCHIVE, "r:gz") as archive:
            hdf5_members = sorted(
                member.name
                for member in archive.getmembers()
                if member.isfile() and member.name.endswith("/processed_data/test/data.hdf5")
            )
    elif AIIO_SAMPLE_EXTRACT_DIR.exists():
        hdf5_members = sorted(
            path.relative_to(AIIO_SAMPLE_EXTRACT_DIR).as_posix()
            for path in AIIO_SAMPLE_EXTRACT_DIR.glob("datasets/our2/indoor/**/processed_data/test/data.hdf5")
        )
    if not hdf5_members:
        return AIIO_SAMPLE_DEFINITIONS
    return [aiio_sample_definition_from_hdf5_member(member) for member in hdf5_members]

