def summarize_aiio_flight_log_samples(presets: list[dict[str, float | str]]) -> dict[str, object]:
    sample_definitions = discover_aiio_test_sample_definitions()
    h5py, np, import_note = aiio_hdf5_modules()
    files_available, file_note = ensure_aiio_sample_files(sample_definitions)
    if h5py is None or np is None or not files_available:
        rows = [
            {
                "row_type": "reference_aiio_hdf5_sample_unavailable",
                "name": "AIIO_sample_analysis_unavailable",
                "source": AIIO_RELEASE_DATASET_URL,
                "archive_path": repo_path(AIIO_ARCHIVE),
                "note": import_note or file_note,
            }
        ]
        return {"summary_csv": write_aiio_flight_log_sample_csv(rows), "rows": rows, "note": import_note or file_note}

    racing = next(row for row in presets if row["preset"] == "racingQuad")
    racing_weight_n = float(racing["mass_kg"]) * G
    racing_total_max_thrust = float(racing["rotor_count"]) * float(racing["max_thrust_n"])
    racing_horizontal_margin = math.sqrt(max(0.0, racing_total_max_thrust * racing_total_max_thrust - racing_weight_n * racing_weight_n))
    racing_total_drag_c_x = float(racing["linear_drag_coefficient"]) + float(racing["body_drag_x"])
    racing_max_rpm = float(racing["max_rpm_from_k"])
    racing_hover_rpm = rpm_from_k_thrust(float(racing["k_n_per_rad2"]), float(racing["hover_thrust_per_rotor_n"]))
    racing_blade_count = float(racing.get("rotor_blade_count", 3.0))
    racing_max_blade_pass_hz = racing_max_rpm / 60.0 * racing_blade_count
    racing_gyro_lpf_hz = float(racing.get("gyro_low_pass_hz", float("nan")))

    rows: list[dict[str, float | str]] = []
    for sample in sample_definitions:
        hdf5_path = aiio_member_target(str(sample["hdf5_member"]))
        groundtruth_path = aiio_member_target(str(sample["groundtruth_member"]))
        metadata_path = aiio_member_target(str(sample["metadata_member"]))
        with h5py.File(hdf5_path, "r") as handle:  # type: ignore[attr-defined]
            ts = np.asarray(handle["ts"][()], dtype=float)  # type: ignore[attr-defined]
            rotor_spd = np.asarray(handle["rotor_spd"][()], dtype=float)  # type: ignore[attr-defined]
            throttle = np.asarray(handle["throttle"][()], dtype=float).reshape(-1)  # type: ignore[attr-defined]
            gyro = np.asarray(handle["gyro_calib"][()], dtype=float)  # type: ignore[attr-defined]
            accel = np.asarray(handle["accel_calib"][()], dtype=float)  # type: ignore[attr-defined]
            traj = np.asarray(handle["traj_target"][()], dtype=float)  # type: ignore[attr-defined]

        dt_values = np.diff(ts) if ts.size > 1 else np.asarray([], dtype=float)  # type: ignore[attr-defined]
        positive_dt = dt_values[dt_values > 0.0]
        median_dt_s = float(np.median(positive_dt)) if positive_dt.size else float("nan")  # type: ignore[attr-defined]
        sample_rate_hz = 1.0 / median_dt_s if median_dt_s > 0.0 else float("nan")
        duration_s = float(ts[-1] - ts[0]) if ts.size > 1 else float("nan")

        if traj.ndim == 2 and traj.shape[1] >= 10:
            velocity = traj[:, 7:10]
            speed = np.linalg.norm(velocity, axis=1)  # type: ignore[attr-defined]
        else:
            speed = np.asarray([], dtype=float)  # type: ignore[attr-defined]
        finite_speed = speed[np.isfinite(speed)]  # type: ignore[attr-defined]

        rotor_flat = rotor_spd.reshape(-1)
        rotor_finite = rotor_flat[np.isfinite(rotor_flat)]  # type: ignore[attr-defined]
        rotor_nonzero = rotor_finite[rotor_finite > 0.0]
        rotor_basis = rotor_nonzero if rotor_nonzero.size else rotor_finite
        throttle_finite = throttle[np.isfinite(throttle)]  # type: ignore[attr-defined]

        def pct(values: object, percentile: float) -> float:
            return float(np.percentile(values, percentile)) if getattr(values, "size", 0) else float("nan")  # type: ignore[attr-defined]

        def vec_dynamic_rms(values: object) -> float:
            if getattr(values, "ndim", 0) != 2 or getattr(values, "shape", (0, 0))[0] == 0:
                return float("nan")
            centered = values - np.mean(values, axis=0)  # type: ignore[operator,attr-defined]
            return float(math.sqrt(float(np.mean(np.sum(centered * centered, axis=1)))))  # type: ignore[attr-defined]

        gyro_norm = np.linalg.norm(gyro, axis=1) if gyro.ndim == 2 and gyro.shape[0] else np.asarray([], dtype=float)  # type: ignore[attr-defined]
        accel_norm = np.linalg.norm(accel, axis=1) if accel.ndim == 2 and accel.shape[0] else np.asarray([], dtype=float)  # type: ignore[attr-defined]
        speed_max = float(np.max(finite_speed)) if finite_speed.size else float("nan")  # type: ignore[attr-defined]
        rotor_max = float(np.max(rotor_basis)) if rotor_basis.size else float("nan")  # type: ignore[attr-defined]
        rotor_p95 = pct(rotor_basis, 95.0)
        sample_max_bpf_3blade = rotor_max / 60.0 * 3.0 if math.isfinite(rotor_max) else float("nan")
        sample_p95_bpf_3blade = rotor_p95 / 60.0 * 3.0 if math.isfinite(rotor_p95) else float("nan")
        current_drag_at_vmax = racing_total_drag_c_x * speed_max * speed_max if math.isfinite(speed_max) else float("nan")
        required_thrust_at_vmax = math.hypot(racing_weight_n, current_drag_at_vmax) if math.isfinite(current_drag_at_vmax) else float("nan")

        row: dict[str, float | str] = {
            "row_type": "reference_aiio_hdf5_sample",
            "name": str(sample["name"]),
            "source": AIIO_RELEASE_DATASET_URL,
            "repo_source": AIIO_REPO_URL,
            "paper_source": AIIO_ARXIV_HTML_URL,
            "archive_path": repo_path(AIIO_ARCHIVE),
            "hdf5_path": repo_path(hdf5_path),
            "metadata_path": repo_path(metadata_path),
            "groundtruth_path": repo_path(groundtruth_path),
            "mode": str(sample["mode"]),
            "trajectory": str(sample["trajectory"]),
            "sequence": str(sample["sequence"]),
            "split": str(sample["split"]),
            "reference_speed_label": str(sample["reference_speed_label"]),
            "reference_speed_m_s": float(sample["reference_speed_m_s"]),
            "rosbag_metadata_duration_s": aiio_metadata_duration_s(metadata_path),
            "groundtruth_row_count": aiio_groundtruth_row_count(groundtruth_path),
            "hdf5_sample_count": int(ts.size),
            "duration_s": duration_s,
            "median_dt_s": median_dt_s,
            "sample_rate_hz": sample_rate_hz,
            "speed_p50_m_s": pct(finite_speed, 50.0),
            "speed_p95_m_s": pct(finite_speed, 95.0),
            "speed_p99_m_s": pct(finite_speed, 99.0),
            "speed_max_m_s": speed_max,
            "speed_max_over_reference_label": speed_max / float(sample["reference_speed_m_s"]) if float(sample["reference_speed_m_s"]) > 0.0 and math.isfinite(speed_max) else float("nan"),
            "rotor_spd_zero_fraction": float(np.sum(rotor_finite == 0.0) / rotor_finite.size) if rotor_finite.size else float("nan"),  # type: ignore[attr-defined]
            "rotor_spd_p50_reported_units": pct(rotor_basis, 50.0),
            "rotor_spd_p95_reported_units": rotor_p95,
            "rotor_spd_p99_reported_units": pct(rotor_basis, 99.0),
            "rotor_spd_max_reported_units": rotor_max,
            "throttle_p50": pct(throttle_finite, 50.0),
            "throttle_p95": pct(throttle_finite, 95.0),
            "throttle_max": float(np.max(throttle_finite)) if throttle_finite.size else float("nan"),  # type: ignore[attr-defined]
            "gyro_vector_dynamic_rms_rad_s": vec_dynamic_rms(gyro),
            "gyro_vector_norm_p95_rad_s": pct(gyro_norm, 95.0),
            "gyro_vector_norm_max_rad_s": float(np.max(gyro_norm)) if getattr(gyro_norm, "size", 0) else float("nan"),  # type: ignore[attr-defined]
            "accel_vector_dynamic_rms_m_s2": vec_dynamic_rms(accel),
            "accel_vector_norm_p95_m_s2": pct(accel_norm, 95.0),
            "accel_vector_norm_max_m_s2": float(np.max(accel_norm)) if getattr(accel_norm, "size", 0) else float("nan"),  # type: ignore[attr-defined]
            "blade_pass_hz_if_mech_rpm_3blade_p95": sample_p95_bpf_3blade,
            "blade_pass_hz_if_mech_rpm_3blade_max": sample_max_bpf_3blade,
            "current_racing_hover_rpm": racing_hover_rpm,
            "current_racing_max_rpm": racing_max_rpm,
            "current_racing_max_blade_pass_hz": racing_max_blade_pass_hz,
            "current_racing_gyro_lpf_hz": racing_gyro_lpf_hz,
            "rotor_spd_max_over_current_racing_max_rpm": rotor_max / racing_max_rpm if racing_max_rpm > 0.0 and math.isfinite(rotor_max) else float("nan"),
            "blade_pass_max_over_current_racing_max_blade_pass": sample_max_bpf_3blade / racing_max_blade_pass_hz if racing_max_blade_pass_hz > 0.0 and math.isfinite(sample_max_bpf_3blade) else float("nan"),
            "current_racing_gyro_lpf_over_sample_max_bpf": racing_gyro_lpf_hz / sample_max_bpf_3blade if sample_max_bpf_3blade > 0.0 and math.isfinite(racing_gyro_lpf_hz) else float("nan"),
            "current_racing_x_drag_at_sample_vmax_n": current_drag_at_vmax,
            "current_racing_x_drag_at_sample_vmax_over_margin": current_drag_at_vmax / racing_horizontal_margin if racing_horizontal_margin > 0.0 and math.isfinite(current_drag_at_vmax) else float("nan"),
            "current_racing_required_total_thrust_over_max_at_sample_vmax": required_thrust_at_vmax / racing_total_max_thrust if racing_total_max_thrust > 0.0 and math.isfinite(required_thrust_at_vmax) else float("nan"),
            "current_racing_tilt_deg_for_drag_balance_at_sample_vmax": math.degrees(math.atan2(current_drag_at_vmax, racing_weight_n)) if math.isfinite(current_drag_at_vmax) else float("nan"),
            "note": "Parsed from AI-IO processed_data/test HDF5. rotor_spd is kept in dataset reported units; blade-pass fields assume those units are mechanical RPM and should be rechecked before absolute motor fitting.",
        }
        if rotor_spd.ndim == 2:
            for motor_index in range(min(4, rotor_spd.shape[1])):
                motor_values = rotor_spd[:, motor_index]
                motor_finite = motor_values[np.isfinite(motor_values)]  # type: ignore[attr-defined]
                motor_nonzero = motor_finite[motor_finite > 0.0]
                motor_basis = motor_nonzero if motor_nonzero.size else motor_finite
                row[f"rotor{motor_index}_spd_mean_reported_units"] = float(np.mean(motor_basis)) if motor_basis.size else float("nan")  # type: ignore[attr-defined]
                row[f"rotor{motor_index}_spd_max_reported_units"] = float(np.max(motor_basis)) if motor_basis.size else float("nan")  # type: ignore[attr-defined]
        rows.append(row)

    return {"summary_csv": write_aiio_flight_log_sample_csv(rows), "rows": rows, "note": file_note}


