    lines.append("")
    physical_prop_rows = rotor_inertia_summary.get("prop_reference_rows", [])
    if physical_prop_rows:
        lines.append("| Physical prop mass reference | diameter | blades | mass | I c=0.25 | I c=1/3 | I c=0.5 |")
        lines.append("|---|---:|---:|---:|---:|---:|---:|")
        for row in physical_prop_rows:
            item = row  # type: ignore[assignment]
            pitch_text = f"x{fmt(float(item['pitch_in']), 2)}" if item.get("pitch_in") != "" else ""
