        lines.append(f"Physical prop mass rows sharpen the interpretation: `racingQuad` is below 5-inch prop-only uniform inertia (`{fmt(min(racing_uniform_ratios), 2)}..{fmt(max(racing_uniform_ratios), 2)}x`), while `cinewhoop` is far above 3-inch/D90 prop-only inertia (`{fmt(min(cine_uniform_ratios), 1)}..{fmt(max(cine_uniform_ratios), 1)}x`).{heavy_note}")
