    write_summary_csv(static, forward, mqtb, mqtb_current_summary, open_models, presets, comparisons, zju_ground, ground_rows, zju_ground_model_summary, surface_summary, precipitation_summary, vrs_rows, vrs_propwash_summary, battery_ir_rows, high_c_lipo_summary, battery_temp_rows, battery_ocv_soc_summary, battery_dynamic_pulse_summary, nasa_battery_impedance, high_current_eis_summary, motor_thermal_summary, coaxial_rows, coaxial_interference_summary, motor_response_rows, esc_electrical_summary, rotor_forward_flow_summary, rotor_blade_dissymmetry_summary, prop_geometry_pitch_summary, rotor_inertia_summary, rotor_arm_flex_coning_summary, contact_summary, propeller_damage_summary, inertia_rows, drag_rows, airframe_drag_summary, timing_rows, rc_esc_timing_summary, control_rate_summary, imu_rows, wind_rows, atmosphere_rows, tip_mach_compressibility_summary, barometer_summary, blackbox_summary, mendeley_ecm)
    write_markdown(static, forward, mqtb, command_rows, mqtb_current_summary, open_models, presets, comparisons, battery, zju_ground, ground_rows, zju_ground_model_summary, surface_summary, precipitation_summary, vrs_rows, vrs_propwash_summary, battery_ir_rows, high_c_lipo_summary, battery_temp_rows, battery_ocv_soc_summary, battery_dynamic_pulse_summary, nasa_battery_impedance, high_current_eis_summary, motor_thermal_summary, coaxial_rows, coaxial_interference_summary, motor_response_rows, esc_electrical_summary, rotor_forward_flow_summary, rotor_blade_dissymmetry_summary, prop_geometry_pitch_summary, rotor_inertia_summary, rotor_arm_flex_coning_summary, contact_summary, propeller_damage_summary, inertia_rows, drag_rows, airframe_drag_summary, timing_rows, rc_esc_timing_summary, control_rate_summary, imu_rows, wind_rows, atmosphere_rows, tip_mach_compressibility_summary, barometer_summary, blackbox_summary, mendeley_ecm)
